#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>
#include <string_view>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket pkt;

    // Create a reader over the input buffer
    hexi::reader r(buffer);

    // 1. Read packet_id
    r.read(pkt.packet_id);

    // 2. Read username using a length-prefixed string
    r.read(hexi::prefixed(pkt.username));

    // 3. Read scores count, then read the scores vector
    uint32_t score_count = 0;
    r.read(score_count);
    pkt.scores.resize(score_count);
    r.read_container(pkt.scores);

    // 4. Read metadata as null-terminated string (zero-copy read to string_view, then copy)
    std::string_view meta_view;
    r.read(hexi::null_terminated(meta_view));
    pkt.metadata.assign(meta_view.data(), meta_view.size());

    // 5. Skip any remaining padding bytes (if any)
    auto remaining = r.remaining();
    if (!remaining.empty()) {
        r.skip(remaining.size());
    }

    return pkt;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info{};

    hexi::reader r(buffer);

    // 1. Use span() to get a zero-copy view of the packet_id (first 4 bytes)
    {
        auto id_span = r.span<uint32_t>(1);
        // Interpret as little-endian/binary uint32_t
        info.packet_id = *id_span.data();
    }

    // 2. Read username using prefixed adaptor to get a string_view (zero-copy)
    r.read(hexi::prefixed(info.username));

    // 3. Skip the scores vector without reading its elements:
    //    - Read count
    //    - Skip count * sizeof(uint32_t) bytes
    uint32_t score_count = 0;
    r.read(score_count);
    std::size_t bytes_to_skip = static_cast<std::size_t>(score_count) * sizeof(uint32_t);
    r.skip(bytes_to_skip);

    return info;
}
