struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Create a Hexi reader over the buffer
    hexi::Reader reader{buffer};

    // Get a zero-copy span view over the header bytes
    auto header_span = reader.span<std::byte>(sizeof(PacketHeader));

    // Interpret the span as a PacketHeader without copying
    // (assuming the buffer is properly aligned and in native endianness)
    const auto* header_ptr =
        reinterpret_cast<const PacketHeader*>(header_span.data());

    return *header_ptr;
}

