#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create a Hexi buffer adaptor over the source buffer (const version)
    auto adaptor = hexi::make_buffer_adaptor(source_buffer.data(), source_buffer.size());

    // Clamp the number of bytes to read to the source buffer size
    const size_t readable = std::min(bytes_to_read, adaptor.size());

    // Prepare destination buffer
    std::vector<uint8_t> dest(readable);

    // Read from the adaptor into dest
    if (readable > 0) {
        adaptor.read(dest.data(), readable);
    }

    return dest;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Ensure the destination buffer is large enough
    if (dest_buffer.size() < source_data.size()) {
        dest_buffer.resize(source_data.size());
    }

    // Create a Hexi buffer adaptor over the destination buffer (non-const version)
    auto adaptor = hexi::make_buffer_adaptor(dest_buffer.data(), dest_buffer.size());

    // Clamp the bytes to write to the destination adaptor size
    const size_t writable = std::min(source_data.size(), adaptor.size());

    // Write from source_data into the adaptor
    if (writable > 0) {
        adaptor.write(source_data.data(), writable);
    }
}
