#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    using namespace hexi;

    DataResult result{};
    result.data_type = 0;

    // Wrap the incoming buffer with a buffer_adaptor (non-owning)
    buffer_adaptor buf(buffer.data(), buffer.size());

    // 1) Preview the first byte (data_type) without advancing the read pointer.
    //    We use a temporary binary_stream for the peek so the original
    //    adaptor's read position is not modified.
    {
        buffer_adaptor peek_adaptor = buf;      // copy, same underlying data, own cursor
        binary_stream peek_stream(peek_adaptor);
        if (peek_stream.available_read() < sizeof(uint8_t)) {
            // Not enough data to even read the type; return default result
            return result;
        }
        peek_stream >> result.data_type;
    }

    // 2) Now create a real binary_stream on the original adaptor and read for real
    binary_stream stream(buf);

    // Check that we have at least the header (data_type + item_count)
    constexpr std::size_t header_size = sizeof(uint8_t) + sizeof(uint32_t);
    if (stream.available_read() < header_size) {
        return result;
    }

    // Read the header: data_type and item_count
    uint8_t data_type = 0;
    uint32_t item_count = 0;

    stream >> data_type;
    stream >> item_count;
    result.data_type = data_type;

    // 3) Check if the remaining data is sufficient for all items
    std::size_t item_bytes = 0;
    if (data_type == 0) {
        // integers
        item_bytes = static_cast<std::size_t>(item_count) * sizeof(uint32_t);
    } else if (data_type == 1) {
        // floats
        item_bytes = static_cast<std::size_t>(item_count) * sizeof(float);
    } else {
        // Unknown type; return header info only
        return result;
    }

    if (stream.available_read() < item_bytes) {
        // Not enough data; do not attempt to read items
        return result;
    }

    // 4) Read items according to data type
    if (data_type == 0) {
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else { // data_type == 1
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    }

    return result;
}
