#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    using namespace hexi;

    // Create a buffer_adaptor from the input span
    buffer_adaptor adaptor{buffer.data(), buffer.size()};

    // Get the current read pointer and remaining size
    const uint8_t* read_ptr = adaptor.read_ptr();
    std::size_t available = adaptor.readable_size();

    // Ensure there is enough data for the header
    constexpr std::size_t header_size =
        sizeof(std::uint32_t) + 2 * sizeof(std::uint16_t);
    if (available < header_size) {
        throw std::runtime_error("Insufficient data for PacketHeader");
    }

    // Create a binary_stream over the adaptor
    binary_stream stream{adaptor};

    // Get a zero-copy view of the header bytes
    // (this does not advance the stream position)
    std::span<const std::byte> header_view = stream.peek_span(header_size);

    // Interpret the span as a PacketHeader (assuming proper alignment and endianness)
    const auto* header_bytes =
        reinterpret_cast<const std::byte*>(header_view.data());
    PacketHeader header{};

    // Manually decode to keep the example explicit and endianness-agnostic
    std::size_t offset = 0;

    auto read_u32 = [&header_bytes, &offset]() {
        std::uint32_t v = 0;
        v |= static_cast<std::uint32_t>(std::to_integer<std::uint8_t>(header_bytes[offset + 0])) << 0;
        v |= static_cast<std::uint32_t>(std::to_integer<std::uint8_t>(header_bytes[offset + 1])) << 8;
        v |= static_cast<std::uint32_t>(std::to_integer<std::uint8_t>(header_bytes[offset + 2])) << 16;
        v |= static_cast<std::uint32_t>(std::to_integer<std::uint8_t>(header_bytes[offset + 3])) << 24;
        offset += 4;
        return v;
    };

    auto read_u16 = [&header_bytes, &offset]() {
        std::uint16_t v = 0;
        v |= static_cast<std::uint16_t>(std::to_integer<std::uint8_t>(header_bytes[offset + 0])) << 0;
        v |= static_cast<std::uint16_t>(std::to_integer<std::uint8_t>(header_bytes[offset + 1])) << 8;
        offset += 2;
        return v;
    };

    header.magic   = read_u32();
    header.version = read_u16();
    header.flags   = read_u16();

    return header;
}
