    // Write header
    {
        const std::size_t bytes = sizeof(header);
        auto out = buffer.prepare(bytes);
        std::memcpy(out.data(), &header, bytes);
        buffer.commit(bytes);
    }

    // Write data array (if any)
    if (!data.empty()) {
        const std::size_t bytes = data.size();
        auto out = buffer.prepare(bytes);
        std::memcpy(out.data(), data.data(), bytes);
        buffer.commit(bytes);
    }
