```cpp
#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer,
                                           size_t bytes_to_peek) {
    std::vector<uint8_t> result;

    // Determine how much data is actually available to read
    const std::size_t available = buffer.readable_size();
    const std::size_t to_copy   = std::min(available, bytes_to_peek);

    if (to_copy == 0) {
        return result;
    }

    result.resize(to_copy);

    // dynamic_buffer provides const access to the readable data without consuming it.
    // We assume Hexi exposes a way to get a pointer (or span) to the readable region
    // without advancing the read cursor. A common pattern is something like:
    //
    //   auto data = buffer.read_data();        // returns pointer/span to readable bytes
    //   auto size = buffer.readable_size();    // how many bytes are readable
    //
    // and *not* calling buffer.advance_read(...) keeps the cursor unchanged.
    //
    // Since we do not have the exact Hexi API here, we use the typical interface:
    //   const uint8_t* data = buffer.read_data();
    //
    // and copy from that pointer.

    const uint8_t* data = buffer.read_data();  // non-consuming access

    std::copy_n(data, to_copy, result.data());

    // Note: We intentionally do NOT call buffer.advance_read(...) here,
    // so the read cursor remains unchanged and the data is only "peeked".

    return result;
}
```

