#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<typename T>
void convert_from_big_endian_inplace(T& value) {
    // Interpret the stored bytes as big-endian and convert them to native-endian in-place.
    // Hexi provides hexi::endian::from_big which returns a converted value; assign it back.
    value = hexi::endian::from_big(value);
}

template<typename T>
void convert_from_little_endian_inplace(T& value) {
    // Interpret the stored bytes as little-endian and convert them to native-endian in-place.
    value = hexi::endian::from_little(value);
}

template<std::endian from, std::endian to, typename T>
void convert_endianness_inplace(T& value) {
    if constexpr (from == to) {
        // No conversion necessary
        return;
    } else if constexpr (from == std::endian::big && to == std::endian::native) {
        convert_from_big_endian_inplace(value);
    } else if constexpr (from == std::endian::little && to == std::endian::native) {
        convert_from_little_endian_inplace(value);
    } else if constexpr (from == std::endian::native && to == std::endian::big) {
        // Convert native-endian stored value to big-endian representation in-place.
        value = hexi::endian::to_big(value);
    } else if constexpr (from == std::endian::native && to == std::endian::little) {
        // Convert native-endian stored value to little-endian representation in-place.
        value = hexi::endian::to_little(value);
    } else if constexpr (from == std::endian::big && to == std::endian::little) {
        // Big-endian -> native -> little-endian
        convert_from_big_endian_inplace(value);
        value = hexi::endian::to_little(value);
    } else if constexpr (from == std::endian::little && to == std::endian::big) {
        // Little-endian -> native -> big-endian
        convert_from_little_endian_inplace(value);
        value = hexi::endian::to_big(value);
    }
}
