#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

// 1. Preview data without consuming (without advancing read pointer)
template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(
    const hexi::detail::intrusive_storage<block_size>& storage,
    size_t bytes_to_preview
) {
    std::vector<uint8_t> result;
    result.reserve(bytes_to_preview);

    // Hexi intrusive_storage exposes read access via read_some with a callback
    // or const_iterators over readable regions. Since we can't mutate the read
    // offset, we use const iteration over readable chunks.
    //
    // Assumed API (typical for intrusive_storage):
    //   storage.cbegin_read() / storage.cend_read()
    // that iterate over contiguous readable blocks as `std::span<const uint8_t>`-like
    // objects, or a similar range interface.
    //
    // If your actual Hexi version uses a different API, adjust the iteration
    // accordingly (the logic stays the same: walk readable segments, copy up
    // to bytes_to_preview bytes).

    size_t remaining = bytes_to_preview;

    for (auto it = storage.cbegin_read(); it != storage.cend_read() && remaining > 0; ++it) {
        auto span = *it; // a contiguous readable region
        const size_t chunk_size = std::min(remaining, span.size());

        result.insert(result.end(), span.data(), span.data() + chunk_size);
        remaining -= chunk_size;
    }

    return result;
}

// 2. Buffer status information
template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status{};

    // Typical intrusive_storage API:
    //   readable_bytes() -> bytes currently available to read
    //   writable_bytes() -> free space available for writing
    //
    // If your actual Hexi version uses size_readable()/size_writable() or
    // similar names, adjust the calls below.

    status.readable_size = storage.readable_bytes();
    status.free_space    = storage.writable_bytes();

    return status;
}

// 3. Reset both read and write offsets
template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Typical intrusive_storage API for clearing:
    //   clear() -> drop all data, reset read/write offsets.
    //
    // If your version uses reset()/reset_read()/reset_write()/consume_all(),
    // choose the variant that leaves the buffer empty and offsets at zero.

    storage.clear();
}
