#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>
#include <algorithm>   // for std::min
#include <stdexcept>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path,
                                    size_t bytes_to_read) {
    // Open file_buffer for reading (mode may vary depending on Hexi API; here we assume)
    hexi::file_buffer fb(file_path, hexi::open_mode::read);

    // Determine how many bytes are actually available to read
    const auto available = fb.readable_size();
    const auto to_read   = std::min(available, bytes_to_read);

    std::vector<uint8_t> buffer(to_read);
    if (to_read > 0) {
        const auto read_count = fb.read(buffer.data(), to_read);
        buffer.resize(read_count);  // in case fewer bytes were read
    }

    return buffer;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path,
                                       size_t bytes_to_preview) {
    // Open file_buffer for reading
    hexi::file_buffer fb(file_path, hexi::open_mode::read);

    // Determine how many bytes are available to preview
    const auto available = fb.readable_size();
    const auto to_preview = std::min(available, bytes_to_preview);

    std::vector<uint8_t> buffer(to_preview);
    if (to_preview > 0) {
        // Save current read position
        const auto original_pos = fb.tell();

        // Read data into buffer
        const auto read_count = fb.read(buffer.data(), to_preview);
        buffer.resize(read_count);

        // Restore original position so the read pointer is not advanced
        fb.seek(original_pos);
    }

    return buffer;
}

void write_file_data(const std::filesystem::path& file_path,
                     const std::vector<uint8_t>& data) {
    // Open file_buffer for writing (create/truncate)
    hexi::file_buffer fb(file_path, hexi::open_mode::write);

    const auto total = data.size();
    size_t written_total = 0;

    while (written_total < total) {
        const auto written = fb.write(data.data() + written_total,
                                      total - written_total);
        if (written == 0) {
            throw std::runtime_error("Failed to write to file: " + file_path.string());
        }
        written_total += written;
    }

    // Ensure data is flushed to disk if Hexi provides flush
    fb.flush();
}

