```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>
#include <algorithm> // for std::min

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Open the file with Hexi's file_buffer
    hexi::file_buffer fb(file_path.string(), hexi::file_mode::read);

    // Remember current read position so we can restore it afterward
    auto original_pos = fb.tellg();

    // Determine how many bytes we can safely preview
    fb.seekg(0, hexi::seek_origin::end);
    auto file_size = fb.tellg();
    fb.seekg(original_pos, hexi::seek_origin::begin);

    size_t bytes_to_read = static_cast<size_t>(
        std::min<uint64_t>(header_size, file_size - original_pos)
    );

    std::vector<uint8_t> header(bytes_to_read);

    if (bytes_to_read > 0) {
        // Read header starting from the current position, but restore position afterward
        auto temp_pos = fb.tellg();
        fb.read(reinterpret_cast<char*>(header.data()), bytes_to_read);
        fb.seekg(temp_pos, hexi::seek_origin::begin);
    }

    return header;
}
```

