                          const std::vector<uint8_t>& data) {
    // Determine how many bytes we can actually write
    const std::size_t writable = std::min<std::size_t>(data.size(), buffer.capacity() - buffer.size());

    // Write the bytes into the buffer
    for (std::size_t i = 0; i < writable; ++i) {
        buffer.push_back(static_cast<std::byte>(data[i]));
    }
}

template<size_t buffer_size = 1024>
