                                           size_t bytes_to_read) {
    // Determine how many bytes we can actually read
    const std::size_t readable = std::min<std::size_t>(bytes_to_read, buffer.size());

    std::vector<uint8_t> result;
    result.reserve(readable);

    // Read the bytes from the buffer
    for (std::size_t i = 0; i < readable; ++i) {
        std::byte b = buffer.front();
        buffer.pop_front();
        result.push_back(static_cast<uint8_t>(b));
    }

    return result;
}
