template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer,
                                         size_t bytes_to_preview) {
    // Do not modify the buffer (no non-const operations), so the read pointer stays unchanged.
    // Assume Hexi provides const accessors to the readable region of the buffer.
    // Typical static_buffer interface includes:
    //   size_t readable_size() const;
    //   const std::byte* read_data() const;
    //
    // We use these to copy out up to bytes_to_preview bytes.

    const size_t available = buffer.readable_size();
    const size_t to_copy = std::min(available, bytes_to_preview);

    std::vector<uint8_t> result;
    result.reserve(to_copy);

    const std::byte* src = buffer.read_data();
    for (size_t i = 0; i < to_copy; ++i) {
        result.push_back(static_cast<uint8_t>(src[i]));
    }

    return result;
}
