#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <string>
#include <cstdint>

void write_string_to_stream(hexi::pmc::binary_stream_writer& writer, const std::string& str) {
    // Write size as a 32-bit unsigned integer, then the string bytes
    const std::uint32_t size = static_cast<std::uint32_t>(str.size());
    writer.write(size);
    if (!str.empty()) {
        writer.write_bytes(reinterpret_cast<const std::uint8_t*>(str.data()), size);
    }
}

std::string read_string_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Read size, then that many bytes into a std::string
    std::uint32_t size = 0;
    reader.read(size);

    std::string result;
    if (size == 0) {
        return result;
    }

    result.resize(size);
    reader.read_bytes(reinterpret_cast<std::uint8_t*>(&result[0]), size);
    return result;
}
