#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>   // for std::memcmp

// Peek raw bytes from the buffer without advancing the read pointer.
// Uses the non-template copy() overload that takes a void* and length.
void peek_data_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                           void* data,
                           std::size_t length) {
    // copy() on a const buffer_adaptor reference does not advance the read pointer.
    const auto& cbuf = static_cast<const hexi::pmc::buffer_adaptor<std::vector<std::byte>>&>(buffer);
    cbuf.copy(data, length);
}

// Peek a typed value from the buffer without advancing the read pointer.
// Uses the template copy<T>() overload to copy a single value.
template<typename T>
void peek_value_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, T& value) {
    const auto& cbuf = static_cast<const hexi::pmc::buffer_adaptor<std::vector<std::byte>>&>(buffer);
    cbuf.template copy<T>(value);
}

// Peek data and compare it with expected without consuming from the buffer.
bool peek_and_compare(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                      const void* expected,
                      std::size_t length) {
    // Create a temporary buffer to hold the peeked data.
    std::vector<std::byte> tmp(length);

    // Reuse the peek function to copy without advancing.
    peek_data_from_buffer(buffer, tmp.data(), length);

    // Compare with expected.
    return std::memcmp(expected, tmp.data(), length) == 0;
}
