#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>   // for std::memcpy
#include <stdexcept> // for std::runtime_error

// Helper to read a trivially copyable type T from the buffer
template <typename T>
T read_pod(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    if (buffer.readable_size() < sizeof(T)) {
        throw std::runtime_error("Not enough data in buffer to read POD value");
    }

    T value;
    // Hexi's buffer_adaptor exposes the underlying contiguous storage via data()
    std::memcpy(&value, buffer.data(), sizeof(T));
    buffer.consume(sizeof(T));
    return value;
}

void skip_bytes_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                          std::size_t bytes) {
    if (buffer.readable_size() < bytes) {
        throw std::runtime_error("Not enough data in buffer to skip requested number of bytes");
    }
    buffer.consume(bytes);
}

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
};

MessageHeader read_header_and_skip_body(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    MessageHeader header{};

    // Read header fields from the buffer in order
    header.message_type = read_pod<uint16_t>(buffer);
    header.body_length  = read_pod<uint32_t>(buffer);

    // Skip the body bytes based on header.body_length
    skip_bytes_in_buffer(buffer, header.body_length);

    return header;
}
