#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>
#include <type_traits>

using namespace hexi::detail;

// Helper: zigzag encode for signed integers
template<typename T>
static typename std::make_unsigned<T>::type zigzag_encode(T value) {
    using Unsigned = typename std::make_unsigned<T>::type;
    // (n << 1) ^ (n >> (bits - 1))
    constexpr int bits = sizeof(T) * 8;
    return (static_cast<Unsigned>(value) << 1) ^
           static_cast<Unsigned>(value >> (bits - 1));
}

// Helper: zigzag decode for signed integers
template<typename T>
static T zigzag_decode(typename std::make_unsigned<T>::type value) {
    using Unsigned = typename std::make_unsigned<T>::type;
    return static_cast<T>((value >> 1) ^ (~(value & 1) + 1));
}

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    using Unsigned = typename std::make_unsigned<T>::type;
    Unsigned u;

    if constexpr (std::is_signed<T>::value) {
        u = zigzag_encode(value);
    } else {
        u = static_cast<Unsigned>(value);
    }

    std::size_t bytes_written = 0;
    while (true) {
        std::uint8_t byte = static_cast<std::uint8_t>(u & 0x7F);
        u >>= 7;
        if (u != 0) {
            byte |= 0x80; // continuation bit
            writer.write(byte);
            ++bytes_written;
        } else {
            writer.write(byte);
            ++bytes_written;
            break;
        }
    }

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    using Unsigned = typename std::make_unsigned<T>::type;
    Unsigned result = 0;
    int shift = 0;

    while (true) {
        std::uint8_t byte = 0;
        reader.read(byte);

        result |= (static_cast<Unsigned>(byte & 0x7F) << shift);
        if ((byte & 0x80) == 0) {
            break; // last byte
        }
        shift += 7;
    }

    if constexpr (std::is_signed<T>::value) {
        return zigzag_decode<T>(result);
    } else {
        return static_cast<T>(result);
    }
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    std::vector<std::uint8_t> buffer;
    buffer.reserve(16);

    hexi::pmc::buffer_adaptor adaptor(buffer);
    hexi::pmc::binary_stream_writer writer(adaptor);

    encode_varint<T>(writer, original_value);

    hexi::pmc::buffer_adaptor read_adaptor(buffer);
    hexi::pmc::binary_stream_reader reader(read_adaptor);

    T decoded_value = decode_varint<T>(reader);

    return decoded_value == original_value;
}
