```cpp
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

/*
 * Check if two memory regions [src, src + src_len) and
 * [dst, dst + dst_len) overlap in address space.
 *
 * Returns true if there is any overlap, false otherwise.
 */
bool check_regions_overlap(const void* src, std::size_t src_len,
                           const void* dst, std::size_t dst_len) {
    // Treat the pointers as byte pointers for arithmetic
    auto src_begin = static_cast<const std::byte*>(src);
    auto dst_begin = static_cast<const std::byte*>(dst);

    auto src_end = src_begin + src_len;
    auto dst_end = dst_begin + dst_len;

    // Two half-open intervals [a,b) and [c,d) overlap iff:
    // a < d && c < b
    return (src_begin < dst_end) && (dst_begin < src_end);
}

/*
 * Safely copy `length` bytes from `source` to `destination`.
 * Returns false if the regions overlap in an unsafe way or
 * if either pointer is null when length > 0.
 *
 * Uses Hexi's memory utilities for the actual copy if appropriate.
 */
bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    if (length == 0) {
        return true;  // nothing to do
    }

    if (!destination || !source) {
        return false; // invalid pointers
    }

    // Check for overlap between source and destination regions
    if (check_regions_overlap(source, length, destination, length)) {
        return false; // unsafe to copy
    }

    // Use standard memcpy for non-overlapping regions
    std::memcpy(destination, source, length);
    return true;
}
