#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min
#include <cstring>   // for std::memcpy

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a backing buffer large enough for the input data
    std::vector<uint8_t> backing_buffer(input_data.size());

    // Create a write adaptor over the backing buffer
    hexi::pmc::buffer_write_adaptor writer(backing_buffer.data(), backing_buffer.size());

    // Check there is enough free space before writing
    if (writer.free() < input_data.size()) {
        // Not enough space: write as much as we can
        std::size_t to_write = writer.free();
        if (to_write > 0) {
            writer.write(input_data.data(), to_write);
        }
        // Adjust logical size to what was actually written
        backing_buffer.resize(to_write);
    } else {
        // Enough space, write all data
        writer.write(input_data.data(), input_data.size());
    }

    // Now read back using a read adaptor
    hexi::pmc::buffer_read_adaptor reader(backing_buffer.data(), backing_buffer.size());

    std::vector<uint8_t> output;
    output.resize(reader.size()); // size() is the readable size

    std::size_t total_to_read = reader.size();
    std::size_t read_so_far = 0;

    while (read_so_far < total_to_read && reader.size() > 0) {
        // Read as much as is currently available
        std::size_t chunk_size = reader.size();
        std::size_t bytes_read =
            reader.read(output.data() + read_so_far, chunk_size);
        if (bytes_read == 0) {
            break; // nothing more to read
        }
        read_so_far += bytes_read;
    }

    // Trim output to the actual number of bytes read (should match total_to_read)
    output.resize(read_so_far);
    return output;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data,
                                                 std::size_t peek_size) {
    // Create a read adaptor over the provided buffer
    hexi::pmc::buffer_read_adaptor reader(buffer_data.data(), buffer_data.size());

    // Determine how many bytes we can actually peek
    std::size_t available = reader.size();
    std::size_t to_peek = std::min(peek_size, available);

    std::vector<uint8_t> peeked;
    peeked.resize(to_peek);

    if (to_peek == 0) {
        return peeked; // empty
    }

    // Use read_ptr() to get pointer to current read position
    const uint8_t* current_read_ptr =
        static_cast<const uint8_t*>(reader.read_ptr());

    // Use copy() to peek at data without advancing the read cursor
    // (assuming copy() has signature: std::size_t copy(void* dst, std::size_t len) const / similar)
    // We copy from the adaptor into our peeked buffer.
    reader.copy(peeked.data(), to_peek);

    // Now actually consume the same amount of data using read()
    // so that the read cursor advances.
    std::vector<uint8_t> consumed;
    consumed.resize(to_peek);
    reader.read(consumed.data(), to_peek);

    // The function's purpose is to return the peeked data (what we saw without
    // advancing initially), so we return 'peeked'.
    // 'consumed' is only used to advance the internal cursor.
    (void)current_read_ptr; // suppress unused variable warning if not otherwise used

    return peeked;
}
```

