#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm>

// Write data in multiple chunks and track buffer state.
// Returns the total number of bytes written.
std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    if (chunks.empty()) {
        return 0;
    }

    // Compute total size of all chunks so we can allocate enough space.
    std::size_t total_input_size = 0;
    for (const auto& c : chunks) {
        total_input_size += c.size();
    }

    // Backing storage for the write adaptor.
    std::vector<uint8_t> buffer(total_input_size, 0);

    // Create write adaptor over the buffer.
    hexi::pmc::buffer_write_adaptor writer(buffer.data(), buffer.size());

    for (const auto& chunk : chunks) {
        std::size_t chunk_offset = 0;

        while (chunk_offset < chunk.size()) {
            // Check available space before each write.
            std::size_t available = writer.free();
            if (available == 0) {
                // No more space in the buffer.
                return writer.size();
            }

            // Write as much as fits from the current chunk.
            std::size_t to_write = std::min(available, chunk.size() - chunk_offset);
            std::size_t written = writer.write(chunk.data() + chunk_offset, to_write);

            chunk_offset += written;

            // If writer wrote less than requested, no more space is available.
            if (written < to_write) {
                return writer.size();
            }
        }
    }

    // Return total bytes stored in the buffer.
    return writer.size();
}

// Read data partially from a buffer in chunks of at most chunk_size.
// Uses size() to track remaining bytes and continues until the adaptor is empty.
// Returns all bytes read (in order) as a single vector.
std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    std::vector<uint8_t> result;
    if (buffer.empty() || chunk_size == 0) {
        return result;
    }

    hexi::pmc::buffer_read_adaptor reader(buffer.data(), buffer.size());
    result.reserve(buffer.size());

    while (reader.size() > 0) {
        // Determine how much to read this iteration.
        std::size_t remaining = reader.size();
        std::size_t to_read = std::min(remaining, chunk_size);

        // Temporary storage for this partial read.
        std::vector<uint8_t> tmp(to_read);
        std::size_t read_bytes = reader.read(tmp.data(), to_read);

        // Append actually read bytes to result.
        result.insert(result.end(), tmp.begin(), tmp.begin() + read_bytes);

        // If fewer bytes were read than requested, we've exhausted the buffer.
        if (read_bytes < to_read) {
            break;
        }
    }

    return result;
}
