#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    // Serialization (const) – write to stream
    void serialise(auto& adaptor) const {
        using namespace hexi;

        // Write sensor_id directly (assumed uint32_t native)
        adaptor.write(sensor_id);

        // Write temperatures vector size (in native uint32_t)
        uint32_t count = static_cast<uint32_t>(temperatures.size());
        adaptor.write(count);

        // Convert each temperature to little-endian and write
        for (float t : temperatures) {
            float tmp = t;
            conditional_reverse(tmp, std::endian::native, std::endian::little);
            adaptor.write(tmp);
        }

        // Convert pressure to little-endian and write
        double p = pressure;
        conditional_reverse(p, std::endian::native, std::endian::little);
        adaptor.write(p);
    }

    // Deserialization (non-const) – read from stream
    void serialise(auto& adaptor) {
        using namespace hexi;

        // Read sensor_id directly
        adaptor.read(sensor_id);

        // Read temperatures vector size
        uint32_t count = 0;
        adaptor.read(count);
        temperatures.resize(count);

        // Read each temperature in little-endian then convert in place
        for (uint32_t i = 0; i < count; ++i) {
            adaptor.read(temperatures[i]);
            little_to_native_inplace(temperatures[i]);
        }

        // Read pressure and convert from little-endian to native
        adaptor.read(pressure);
        little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    using namespace hexi;

    // Create an in-memory output stream / buffer adaptor
    std::vector<uint8_t> buffer;
    buffer.reserve(128); // arbitrary initial capacity

    memory_output_stream adaptor(buffer);
    adaptor.serialise(data);  // calls MeasurementData::serialise(const auto&)

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    using namespace hexi;

    MeasurementData data;
    memory_input_stream adaptor(buffer);
    adaptor.deserialise(data);  // calls MeasurementData::serialise(auto&)

    return data;
}

