    // view will give us a std::string_view without copying.
    std::string_view name_view;
    adaptor.view(name_view);   // if no name is present, this may leave it empty
    info.sensor_name = name_view;

    // Ensure there is enough data for sensor_id
    adaptor.enforce_read_bounds(sizeof(uint32_t));

